/* Custom styles for ATS optimization and visual clarity */

.section h3 {
  font-weight: bold;
  font-size: 14px;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 8px;
}

.experience-item h4 {
  font-weight: bold;
  font-size: 12px;
}

.experience-item .company {
  font-weight: normal;
  font-style: italic;
}

/* Ensure bullets are ATS-friendly */
ul li {
  margin-bottom: 4px;
  line-height: 1.4;
}

/* Professional color scheme */
.section {
  margin-bottom: 16px;
}

/* Clean typography for scanning */
body {
  font-family: 'Arial', 'Calibri', sans-serif;
  font-size: 11px;
  line-height: 1.3;
  color: #333;
}
